#!/usr/bin/env node
/**
 * Renames runner-saved response files under tbo-results/case-NN/ from
 * `step_NN_<noisy_slug>.json` to `<method>Response.json` so they line up
 * with the Request files (matching the convention used in case-05).
 *
 * The Response slug is all-lowercase (e.g. `farequoteResponse.json`,
 * `getbookingdetailsResponse.json`), matching the runner's existing slug.
 * The Request slug is camelCase (already generated by
 * generate-request-bodies.js); the pair is intentionally case-mixed because
 * that's what case-05 already established.
 *
 * Cases handled: 04, 06, 07, 08, 09, 10, 11, 12.
 * Case 05 is skipped (already renamed manually).
 *
 * Safe to re-run; if both old and new exist the script keeps the existing
 * `<method>Response.json` and removes the duplicate `step_*` file.
 */

"use strict";

const fs   = require("fs");
const path = require("path");

const ROOT     = __dirname;
const OUT_BASE = path.join(ROOT, "tbo-results");
const CASES    = ["04", "06", "07", "08", "09", "10", "11", "12"];

// ─── method detection ───────────────────────────────────────────────────────
// Order matters: longer / more specific prefixes first so e.g. `get_calendar_fare`
// matches before a bare `get`. Each entry: regex against the post-step_NN_ slug,
// and the target method slug used in the output filename.
const PATTERNS = [
  { rx: /^get[_-]?calendar[_-]?fare(?:[_\-\s\(]|$)/i,      slug: "getcalendarfare"        },
  { rx: /^update[_-]?calendar[_-]?fare(?:[_\-\s\(]|$)/i,   slug: "updatecalendarfareofday" },
  { rx: /^get[_-]?booking[_-]?details(?:[_\-\s\(]|$)/i,    slug: "getbookingdetails"      },
  { rx: /^getbookingdetails(?:[_\-\s\(]|$)/i,              slug: "getbookingdetails"      },
  { rx: /^authenticate(?:[_\-\s\(]|$)/i,                   slug: "authenticate"           },
  { rx: /^auth(?:[_\-\s\(]|$)/i,                           slug: "authenticate"           },
  { rx: /^pricerbd(?:[_\-\s\(]|$)/i,                       slug: "pricerbd"               },
  { rx: /^farerule(?:[_\-\s\(]|$)/i,                       slug: "farerule"               },
  { rx: /^farequote(?:[_\-\s\(]|$)/i,                      slug: "farequote"              },
  { rx: /^search(?:[_\-\s\(]|$)/i,                         slug: "search"                 },
  { rx: /^ssr(?:[_\-\s\(]|$)/i,                            slug: "ssr"                    },
  { rx: /^book(?:[_\-\s\(]|$)/i,                           slug: "book"                   },
  { rx: /^ticket(?:[_\-\s\(]|$)/i,                         slug: "ticket"                 },
];

// Strip the runner's `step_NN_` prefix. Some files (case 10) double the prefix
// as `step_NN_step_N_<rest>`; peel both off.
function stripStepPrefix(name) {
  let core = name.replace(/^step_\d+_/i, "");
  if (/^step_\d+_/i.test(core)) core = core.replace(/^step_\d+_/i, "");
  return core;
}

function methodSlug(stepFilename) {
  const core = stripStepPrefix(stepFilename.replace(/\.json$/i, ""));
  for (const p of PATTERNS) {
    if (p.rx.test(core)) return p.slug;
  }
  return null;
}

// ─── per-case rename ────────────────────────────────────────────────────────

let renamed = 0, skipped = 0, removed = 0;

for (const c of CASES) {
  const dir = path.join(OUT_BASE, `case-${c}`);
  if (!fs.existsSync(dir)) {
    console.warn(`[skip] ${dir} not found`);
    continue;
  }
  const files = fs.readdirSync(dir).filter((f) => /^step_/i.test(f) && f.endsWith(".json"));
  if (!files.length) {
    console.log(`Case ${c}: no step_* files — nothing to rename.`);
    continue;
  }

  console.log(`\nCase ${c} → ${path.relative(ROOT, dir)}`);

  for (const f of files) {
    const slug = methodSlug(f);
    if (!slug) {
      console.warn(`  [skip] ${f}: no method pattern matched`);
      skipped++;
      continue;
    }
    const dest      = `${slug}Response.json`;
    const fromPath  = path.join(dir, f);
    const destPath  = path.join(dir, dest);

    if (fs.existsSync(destPath)) {
      // Target already exists — drop the duplicate step_* file rather than overwrite.
      if (fs.realpathSync(fromPath) === fs.realpathSync(destPath)) continue;
      fs.unlinkSync(fromPath);
      console.log(`  · ${f} → (already had ${dest}, removed duplicate)`);
      removed++;
      continue;
    }

    fs.renameSync(fromPath, destPath);
    console.log(`  ✓ ${f.padEnd(60)} → ${dest}`);
    renamed++;
  }
}

console.log(`\nDone. renamed: ${renamed}  removed-duplicate: ${removed}  skipped: ${skipped}`);
